#include<bits/stdc++.h>
using namespace std;

/*
Cost of a straight edge is 0
Cost of a reverse edge is 1
Run 0/1 bfs to compute the answer
*/


const int N = 2e5 + 1;
const int INF = 1e9;

vector<pair<int,int>> adj[N]; 
vector<bool> vis(N, 0); 
int d[N];

void bfs(int v) { 
    deque<int> q;
    q.push_back(v);

    d[v] = 0;

    while(!q.empty()) { 
        int u = q.front();
        q.pop_front();

        if(vis[u]) { 
            continue;
        }

        vis[u] = 1; 

        for(auto x: adj[u]) {
            int node = x.first;
            int weight = x.second;

            if(weight == 0) {
                q.push_front(node);
                d[node] = min(d[node], d[u]);
            }
            else {
                q.push_back(node);
                d[node] = min(d[node], d[u] + 1);
            }
        }
    }   
}

int main() {
    int n, m; cin >> n >> m;
    for(int i = 1; i <= n; i++) d[i] = INF;
    for(int i = 0; i < m; i++) {
        int x, y; cin >> x >> y;
        adj[x].push_back({y, 0});
        adj[y].push_back({x, 1});
    }
    bfs(1);

    if(d[n] == INF) {
        cout << "-1";
    }
    else {
        cout << d[n];
    }
    return 0;
}

