import java.util.*;

/*
Cost of a straight edge is 0
Cost of a reverse edge is 1
Run 0/1 bfs to compute the answer
*/

class main {
    static int N = 200001;
    static int INF = 1000000000;
    static List<Pair>[] adj = new ArrayList[N];
    static boolean[] vis = new boolean[N];
    static int[] d = new int[N];

    static class Pair {
        int node;
        int weight;

        Pair(int node, int weight) {
            this.node = node;
            this.weight = weight;
        }
    }

    public static void bfs(int v) {
        Deque<Integer> q = new ArrayDeque<>();
        q.add(v);
        d[v] = 0;

        while (!q.isEmpty()) {
            int u = q.poll();

            if (vis[u]) {
                continue;
            }

            vis[u] = true;

            for (Pair x : adj[u]) {
                int node = x.node;
                int weight = x.weight;

                if (weight == 0) {
                    q.offerFirst(node);
                    d[node] = Math.min(d[node], d[u]);
                } else {
                    q.offerLast(node);
                    d[node] = Math.min(d[node], d[u] + 1);
                }
            }
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        int n = scanner.nextInt();
        int m = scanner.nextInt();

        for (int i = 1; i <= n; i++) {
            adj[i] = new ArrayList<>();
            d[i] = INF;
        }

        for (int i = 0; i < m; i++) {
            int x = scanner.nextInt();
            int y = scanner.nextInt();
            adj[x].add(new Pair(y, 0));
            adj[y].add(new Pair(x, 1));
        }

        bfs(1);

        if (d[n] == INF) {
            System.out.println("-1");
        } else {
            System.out.println(d[n]);
        }
    }
}

